        >
          {children}
        </article>
      </main>

      <TextShare />
      <Navigation prev={prevChapter} next={nextChapter} />
      <OfflineIndicator />

      {/* TOC drawer overlay */}
      {tocOpen && allChapters && (
        <div
          class="pressy-toc-backdrop pressy-toc-backdrop--scroll"
          onClick={(e: MouseEvent) => {
