          <polyline points="9 6 15 12 9 18" />
        </svg>
      </div>

      {/* Chapter boundary hints */}
      {chapterHint === "prev" && effectivePrevChapter && (
        <div
          class="pressy-chapter-hint pressy-chapter-hint--prev"
