    const initialTimer = setTimeout(recalculatePages, 50);

    const observer = new ResizeObserver(() => {
      recalculatePages();
    });
    observer.observe(viewport);

    return () => {
      clearTimeout(initialTimer);
      observer.disconnect();
    };
  }, [recalculatePages]);

