    currentPage,
    totalPages,
    onSaveProgress,
    isMultiChapter,
    chapterRanges,
    activeChapterSlug,
  ]);

  // Determine the effective last chapter slug for rubber-band / next chapter hint
  const effectiveNextChapter = (() => {
