    (e: MouseEvent) => {
      if (isTouchDevice) return;
      const container = containerRef.current;
      if (!container) return;

      const rect = container.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      const third = rect.width / 3;

      if (x < third) {
        setHoverZone("left");
      } else if (x > third * 2) {
        setHoverZone("right");
      } else {
        setHoverZone(null);
      }

