      }
    },
    [isTouchDevice, settingsOpen, tocOpen, bookmarksOpen]
  );

  const handleMouseLeave = useCallback(() => {
    setHoverZone(null);
    if (!settingsOpen && !tocOpen && !bookmarksOpen) {
      if (footerTimerRef.current) clearTimeout(footerTimerRef.current);
