        if (dx > 40 && atStart && effectivePrevChapter) {
          setChapterHint("prev");
        } else if (dx < -40 && atEnd && effectiveNextChapter) {
          setChapterHint("next");
        } else {
          setChapterHint(null);
        }
      } else {
        setChapterHint(null);
      }

      isDraggingRef.current = true;
      setIsDragging(true);
      setDragOffset(offset);
    };

    const onTouchEnd = (e: TouchEvent) => {
      if (!isSwipingRef.current || !isDraggingRef.current) {
        setIsDragging(false);
        setDragOffset(0);
        setChapterHint(null);
        return;
