      const prevRange = chapterRanges.find((r) => r.slug === prevSlug);
      if (prevRange) {
        const prevTotalPages = prevRange.endPage - prevRange.startPage + 1;
        onChapterChange(prevSlug, prevTotalPages - 1, prevTotalPages);
      }
    }
