    currentPage,
    chapterRanges,
    activeChapterSlug,
    isMultiChapter,
    bookBasePath,
    allChapters,
    onChapterChange,
  ]);

  // Save progress when page changes (debounced) — save relative to active chapter
  useEffect(() => {
    if (!onSaveProgress || !hasRestoredRef.current) return;

    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(() => {
      if (isMultiChapter && chapterRanges.length > 0) {
        const activeRange = chapterRanges.find(
          (r) => r.slug === activeChapterSlug
        );
        if (activeRange) {
          const chapterPage = currentPage - activeRange.startPage;
          const chapterTotalPages =
            activeRange.endPage - activeRange.startPage + 1;
          onSaveProgress({
            page: chapterPage,
            totalPages: chapterTotalPages,
            scrollPosition: 0,
            activeChapterSlug,
          });
        }
      } else {
        onSaveProgress({
          page: currentPage,
          totalPages,
          scrollPosition: 0,
        });
      }
    }, 300);

    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, [
    currentPage,
    totalPages,
    onSaveProgress,
    isMultiChapter,
    chapterRanges,
    activeChapterSlug,
  ]);

  // Save progress on page unload
  useEffect(() => {
    if (!onSaveProgress) return;

    const handleUnload = () => {
      if (isMultiChapter && chapterRanges.length > 0) {
        const activeRange = chapterRanges.find(
          (r) => r.slug === activeChapterSlug
        );
        if (activeRange) {
          const chapterPage = currentPage - activeRange.startPage;
          const chapterTotalPages =
            activeRange.endPage - activeRange.startPage + 1;
          onSaveProgress({
            page: chapterPage,
            totalPages: chapterTotalPages,
            scrollPosition: 0,
            activeChapterSlug,
          });
        }
      } else {
        onSaveProgress({
          page: currentPage,
          totalPages,
          scrollPosition: 0,
        });
