async function saveBookmark(bookmark: Bookmark): Promise<void> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readwrite')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.put(bookmark)
    request.onsuccess = () => resolve()
    request.onerror = () => reject(request.error)
  })
}

async function deleteBookmark(id: string): Promise<void> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readwrite')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.delete(id)
    request.onsuccess = () => resolve()
    request.onerror = () => reject(request.error)
  })
}

async function getBookmarksByBook(bookSlug: string): Promise<Bookmark[]> {
  const database = await initDB()
  return new Promise((resolve, reject) => {
    const tx = database.transaction(BOOKMARKS_STORE, 'readonly')
    const store = tx.objectStore(BOOKMARKS_STORE)
    const request = store.getAll()
    request.onsuccess = () => {
      const all: Bookmark[] = request.result || []
      const filtered = all
        .filter(b => b.bookSlug === bookSlug)
        .sort((a, b) => b.createdAt - a.createdAt)
      resolve(filtered)
    }
    request.onerror = () => reject(request.error)
  })
}

