              <svg
                viewBox="0 0 24 24"
                fill={bookmarksOpen ? "currentColor" : "none"}
                stroke="currentColor"
                stroke-width="1.5"
                stroke-linecap="round"
                stroke-linejoin="round"
                width="18"
                height="18"
              >
                <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
              </svg>
            </button>
          )}
          <button
            class="pressy-settings-toggle"
